101	func (s *Service) GetRequest(ctx context.Context, requestID string) (*models.Contract, *models.Handset, error) {
102		if requestID == "" {
103			return nil, nil, fmt.Errorf("request_id is required: %w", terrors.ErrBadRequest)
104		}
105	
106		contract, err := s.store.GetContractByRequestID(ctx, requestID)
107		if err != nil {
108			if errors.Is(err, terrors.ErrNotFound) {
109				return nil, nil, fmt.Errorf("contract not found for request_id: %w", terrors.ErrNotFound)
110			}
111			return nil, nil, fmt.Errorf("failed to get contract by request_id: %w", err)
112		}
113	
114		// If the contract already has all handset details captured at creation time, use them directly
115		// without a storage lookup. This preserves the pricing agreed at time of request.
116		if contract.HandsetName != "" && contract.ContractPrice != "" && contract.RetailPrice != "" && contract.ContractMonths != "" {
117			return contract, nil, nil
118		}
119	
120		handsetUUID, err := uuid.Parse(contract.HandsetID)
121		if err != nil {
122			return nil, nil, fmt.Errorf("invalid handset id on contract: %w", err)
123		}
124	
125		h, err := s.store.GetHandsetByID(ctx, handsetUUID)
126		if err != nil {
127			return nil, nil, fmt.Errorf("failed to get handset for contract: %w", err)
128		}
129	
130		if h.CurrentProperties.RRPPence == 0 || h.CurrentProperties.RentalPricePence == 0 || h.CurrentProperties.ContractTermMonths == 0 {
131			return nil, nil, fmt.Errorf("handset has incomplete pricing data: %w", terrors.ErrFailedValidation)
132		}
133	
134		// If contract has a specific version, find that version's properties
135		if contract.HandsetVersion != "" && contract.HandsetVersion != h.CurrentProperties.Version {
136			for _, v := range h.Versions {
137				if v.Version == contract.HandsetVersion {
138					h.CurrentProperties = v
139					break
140				}
141			}
142		}
143	
144		return contract, h, nil
145	}
