163	func (s *Service) RequestHandsetForService(ctx context.Context, serviceID, customerID, handsetID string) (string, string, error) {
164		if serviceID == "" || customerID == "" || handsetID == "" {
165			return "", "", fmt.Errorf("service_id, customer_id, and handset_id are required: %w", terrors.ErrBadRequest)
166		}
167	
168		handsetUUID, err := uuid.Parse(handsetID)
169		if err != nil {
170			return "", "", fmt.Errorf("invalid handset_id: %w", terrors.ErrBadRequest)
171		}
172	
173		// Check service belongs to customer
174		servicesResp, err := s.myServicesClient.GetServices(ctx, &myservicesapi.GetServicesRequest{
175			CustomerId:   customerID,
176			IncludeEnded: true,
177		})
178		if err != nil {
179			return "", "", fmt.Errorf("failed to retrieve services for customer: %w", err)
180		}
181	
182		found := false
183		for _, svc := range servicesResp.Services {
184			if svc.GetMobileService() != nil && svc.GetMobileService().GetServiceId() == serviceID {
185				found = true
186				if svc.GetMobileService().GetState() != serviceevents.MobileService_LIVE {
187					return "", "", fmt.Errorf("service is not active: %w", terrors.ErrFailedValidation)
188				}
189				break
190			}
191		}
192		if !found {
193			return "", "", fmt.Errorf("service not found for customer: %w", terrors.ErrNotFound)
194		}
195	
196		// Check for existing active contract
197		_, err = s.store.GetActiveContractForService(ctx, serviceID)
198		if err == nil {
199			return "", "", fmt.Errorf("an active handset contract already exists for this service: %w", terrors.ErrFailedValidation)
200		}
201		if !errors.Is(err, terrors.ErrNotFound) {
202			return "", "", fmt.Errorf("failed to check active contract: %w", err)
203		}
204	
205		// Verify handset exists and is in stock
206		h, err := s.store.GetHandsetByID(ctx, handsetUUID)
207		if err != nil {
208			return "", "", fmt.Errorf("handset not found: %w", terrors.ErrNotFound)
209		}
210		if !h.Active {
211			return "", "", fmt.Errorf("handset is not active: %w", terrors.ErrFailedValidation)
212		}
213		if h.QuantityInStock <= 0 {
214			return "", "", fmt.Errorf("handset is out of stock: %w", terrors.ErrFailedValidation)
215		}
216	
217		// Fetch customer information from account-gateway
218		accountResp, err := s.accountClient.GetAccount(ctx, &accountgateway.GetAccountRequest{
219			AccountId: customerID,
220		})
221		if err != nil {
222			return "", "", fmt.Errorf("failed to retrieve account: %w", err)
223		}
224		if accountResp.GetAccount() == nil {
225			return "", "", fmt.Errorf("account response missing account data")
226		}
227	
228		now := time.Now()
229		props := h.CurrentProperties
230		contract := models.Contract{
231			ID:             uuid.New(),
232			ServiceID:      serviceID,
233			CustomerID:     customerID,
234			HandsetID:      handsetID,
235			HandsetName:    fmt.Sprintf("%s %s", props.Manufacturer, props.Model),
236			HandsetVersion: props.Version,
237			ContractPrice:  fmt.Sprintf("%d", props.RentalPricePence),
238			RetailPrice:    fmt.Sprintf("%d", props.RRPPence),
239			ContractMonths: fmt.Sprintf("%d", props.ContractTermMonths),
240			RequestID:      uuid.New().String(),
241			Status:         models.ContractStatusPendingEligibility,
242			CreatedAt:      now,
243			UpdatedAt:      now,
244		}
245	
246		if err = s.store.CreateContract(ctx, contract); err != nil {
247			return "", "", fmt.Errorf("failed to create contract: %w", err)
248		}
249	
250		tlog.WithAttribute("service_id", contract.ServiceID).
251			WithAttribute("customer_id", contract.CustomerID).
252			WithAttribute("contract_id", contract.ID.String()).
253			WithAttribute("request_id", contract.RequestID).
254			WithAttribute("handset_id", contract.HandsetID).
255			Info(ctx, "handset contract created")
256	
257		// Produce lifecycle event
258		if err := s.eventProducer.ProduceMobileHandsetContractRequestedSync(ctx, &serviceevents.MobileHandsetContractRequested{
259			ServiceId:  contract.ServiceID,
260			CustomerId: contract.CustomerID,
261			ContractId: contract.ID.String(),
262			HandsetId:  contract.HandsetID,
263		}); err != nil {
264			tlog.WithError(err).
265				WithAttribute("contract_id", contract.ID.String()).
266				Error(ctx, "failed to produce MobileHandsetContractRequested event")
267		}
268	
269		redirectURL, err := eligibilityRedirectURL(s.eligibilityProviderURL, contract.RequestID)
270		if err != nil {
271			return "", "", err
272		}
273	
274		return contract.RequestID, redirectURL, nil
275	}
