365	// EligibilityStatusUpdate handles status update notifications from the eligibility provider.
366	// For DECLINED and WITHDRAWN statuses, the contract is moved to DECLINED.
367	func (s *Service) EligibilityStatusUpdate(ctx context.Context, requestID, statusStr string) error {
368		// @todo matt - this is a bit of a catch-all for any future status updates from the eligibility provider that require action. we don't really know what the statuses in the proto actually represent at this stage, neither do we know which are terminal states and how they should interact with the success/failure callbacks. consider this method WIP for the time being.
369		if requestID == "" {
370			return fmt.Errorf("request_id is required: %w", terrors.ErrBadRequest)
371		}
372	
373		if statusStr != "DECLINED" && statusStr != "WITHDRAWN" {
374			tlog.WithAttribute("request_id", requestID).
375				WithAttribute("status", statusStr).
376				Info(ctx, "eligibility status update received, no action required")
377			return nil
378		}
379	
380		contract, err := s.store.GetContractByRequestID(ctx, requestID)
381		if err != nil {
382			return fmt.Errorf("failed to get contract: %w", err)
383		}
384	
385		if contract.Status != models.ContractStatusPendingEligibility {
386			tlog.WithAttribute("request_id", requestID).
387				WithAttribute("current_status", string(contract.Status)).
388				Info(ctx, "eligibility status update ignored, contract is not pending eligibility")
389			return nil
390		}
391	
392		if err := s.store.UpdateContractStatus(ctx, requestID, models.ContractStatusDeclined); err != nil {
393			return fmt.Errorf("failed to update contract status: %w", err)
394		}
395	
396		if err := s.eventProducer.ProduceMobileHandsetContractDeclinedSync(ctx, &serviceevents.MobileHandsetContractDeclined{
397			ServiceId:  contract.ServiceID,
398			CustomerId: contract.CustomerID,
399			ContractId: contract.ID.String(),
400			HandsetId:  contract.HandsetID,
401		}); err != nil {
402			tlog.WithError(err).
403				WithAttribute("contract_id", contract.ID.String()).
404				Error(ctx, "failed to produce MobileHandsetContractDeclined event")
405		}
406	
407		tlog.WithAttribute("request_id", requestID).
408			WithAttribute("contract_id", contract.ID.String()).
409			WithAttribute("status", statusStr).
410			Info(ctx, "eligibility status update, contract declined")
411	
412		return nil
413	}
