415	// money converts a pence integer string (e.g. "4200") to a Money message with
416	// the amount expressed in pounds (e.g. "42.00"). The Money type is consumed by
417	// downstream services that treat Amount as a decimal pound value.
418	func money(penceStr string) *serviceevents.Money {
419		pence, err := strconv.Atoi(penceStr)
420		if err != nil {
421			return &serviceevents.Money{Amount: penceStr, Currency: currencyGBP}
422		}
423		return &serviceevents.Money{
424			Amount:   fmt.Sprintf("%.2f", float64(pence)/100),
425			Currency: currencyGBP,
426		}
427	}
