429	func eligibilityRedirectURL(providerURL, requestID string) (string, error) {
430		u, err := url.Parse(providerURL)
431		if err != nil {
432			return "", fmt.Errorf("failed to parse eligibility provider URL: %w", err)
433		}
434	
435		query := u.Query()
436		query.Set("request_id", requestID)
437		u.RawQuery = query.Encode()
438	
439		return u.String(), nil
440	}
