43	func NewStorage(ctx context.Context, mongo tmongo.Mongo, nowFunc func() time.Time) (*storage, error) {
44		db := &storage{
45			Mongo:               mongo,
46			handsetsCollection:  mongo.Client.Database(mongo.Database).Collection(collectionHandsets),
47			contractsCollection: mongo.Client.Database(mongo.Database).Collection(collectionContracts),
48			nowFunc:             nowFunc,
49		}
50	
51		err := db.ensureIndexes(ctx, mongo)
52		if err != nil {
53			return nil, err
54		}
55	
56		return db, nil
