59	func (s storage) ensureIndexes(ctx context.Context, mongoDb tmongo.Mongo) error {
60		err := tmongo.CreateIndexes(ctx, mongoDb, tmongo.CollectionIndexesMap{
61			collectionHandsets: {
62				mongo.IndexModel{
63					Keys:    bson.M{"id": 1},
64					Options: options.Index().SetName("id").SetUnique(true).SetSparse(true),
65				},
66				mongo.IndexModel{
67					Keys:    bson.M{"billID": 1},
68					Options: options.Index().SetName("bill_id").SetUnique(true).SetSparse(true),
69				},
70			},
71			collectionContracts: {
72				mongo.IndexModel{
73					Keys:    bson.M{"id": 1},
74					Options: options.Index().SetName("contract_id").SetUnique(true),
75				},
76				mongo.IndexModel{
77					Keys:    bson.M{"requestId": 1},
78					Options: options.Index().SetName("contract_request_id").SetUnique(true),
79				},
80				mongo.IndexModel{
81					Keys:    bson.M{"serviceId": 1},
82					Options: options.Index().SetName("contract_service_id"),
83				},
84			},
85		})()
86	
87		return err
